function solve(nums) {
    const n = nums.length;
    let max_ans = 0;
    const total_subsets = 1 << n;

    for (let mask = 0; mask < total_subsets; mask++) {
        let and_val = -1;
        let hasB = false;
        let U = [];
        for (let i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                hasB = true;
                and_val &= nums[i];
            } else {
                U.push(nums[i]);
            }
        }
        if (!hasB) {
            and_val = 0;
        }

        let xorU = 0;
        for (let num of U) {
            xorU ^= num;
        }

        if (U.length === 0) {
            let total_val = and_val + 0;
            if (total_val > max_ans) max_ans = total_val;
            continue;
        }

        let xors = new Set();
        xors.add(0);
        for (let num of U) {
            let newXors = new Set(xors);
            for (let x of xors) {
                newXors.add(x ^ num);
            }
            xors = newXors;
        }

        let fU = 0;
        for (let x of xors) {
            let candidate = x + (x ^ xorU);
            if (candidate > fU) fU = candidate;
        }

        let total_val = and_val + fU;
        if (total_val > max_ans) {
            max_ans = total_val;
        }
    }

    return max_ans;
}
```

