    const n = nums.length;
    let totalXOR = 0;
    for (let num of nums) {
        totalXOR ^= num;
    }
    let ans = 0;

    for (let mask = 0; mask < (1 << n); mask++) {
        let andB = -1;
        let xorB = 0;
        let count = 0;
        let R_arr = [];

        for (let i = 0; i < n; i++) {
