        if (count === 0) {
            andB = 0;
        }

        let T = totalXOR ^ xorB;

        let basis = [];
        for (let x of R_arr) {
            for (let b of basis) {
                if ((x ^ b) < x) {
                    x ^= b;
                }
            }
            if (x !== 0) {
                basis.push(x);
            }
        }

        let values = [0];
        for (let b of basis) {
            let newVals = [];
            for (let v of values) {
                newVals.push(v);
                newVals.push(v ^ b);
            }
            values = newVals;
        }

        let maxCandidate = 0;
        for (let a of values) {
            let value = a + (T ^ a);
            if (value > maxCandidate) {
                maxCandidate = value;
            }
